#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N, H, X; scanf("%d %d %d", &N, &H, &X);
        int maxT = 0, t;
        for(int i=0;i<N;i++){
            scanf("%d", &t);
            if(t > maxT) maxT = t;
        }
        if(X + maxT >= H) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

