            int X = Integer.parseInt(st.nextToken());
            st = new StringTokenizer(br.readLine());
            int maxT = 0;
            for (int i = 0; i < N; i++) {
                int t = Integer.parseInt(st.nextToken());
                if (t > maxT) maxT = t;
            }
            sb.append(X + maxT >= H ? "YES" : "NO").append('\n');
        }
        System.out.print(sb.toString());
