import sys

def solve():
    data = list(map(int, sys.stdin.read().strip().split()))
    if not data:
        return
    idx = 0
    T = data[idx]; idx += 1
    out_lines = []
    for _ in range(T):
        N = data[idx]; H = data[idx+1]; X = data[idx+2]; idx += 3
        maxT = 0
        for i in range(N):
            t = data[idx]; idx += 1
            if t > maxT:
                maxT = t
        out_lines.append("YES" if X + maxT >= H else "NO")
    sys.stdout.write("\n".join(out_lines))

if __name__ == "__main__":
    solve()

